const __AR_LBL={Sun:'الأحد',Mon:'الإثنين',Tue:'الثلاثاء',Wed:'الأربعاء',Thu:'الخميس',Fri:'الجمعة',Sat:'السبت',Jan:'يناير',Feb:'فبراير',Mar:'مارس',Apr:'أبريل',May:'مايو',Jun:'يونيو',Jul:'يوليو',Aug:'أغسطس',Sep:'سبتمبر',Oct:'أكتوبر',Nov:'نوفمبر',Dec:'ديسمبر'};
const __ar=()=>document.documentElement.lang==='ar';
const __tlbl=v=>(__ar()&&__AR_LBL[v])?__AR_LBL[v]:v;
window.addEventListener('lateen-lang',()=>{try{if(typeof buildMainChart==='function')buildMainChart();}catch(e){}try{if(typeof renderSaved==='function')renderSaved();if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();const ov=document.getElementById('prod-picker-overlay');if(ov&&ov.classList.contains('open')){const t=__pkT();const ttl=document.getElementById('prod-picker-title');if(ttl)ttl.textContent=t.title;const s=document.getElementById('prod-picker-search');if(s)s.setAttribute('placeholder',t.search);renderProductPicker(s?s.value:'');}}catch(e){}});
const chartData={earnings:{D:{labels:[],sub:[],values:[]},M:{labels:[],sub:[],values:[]},Y:{labels:[],sub:[],values:[]}},pieces:{D:{labels:[],sub:[],values:[]},M:{labels:[],sub:[],values:[]},Y:{labels:[],sub:[],values:[]}}};
const analyticsData={D:{ok:0,fail:0,failPct:0},M:{ok:0,fail:0,failPct:0},Y:{ok:0,fail:0,failPct:0}};
let currentMetric='earnings',currentPeriod='D',mainChart,ringChart;
const __VIS={D:7,M:6,Y:6};
function __pad(n){return n<10?'0'+n:''+n;}
function __ddmmyyyy(d){return __pad(d.getDate())+'/'+__pad(d.getMonth()+1)+'/'+d.getFullYear();}
function buildMainChart(){
  if(mainChart){try{mainChart.destroy();}catch(e){}mainChart=null;}
  const canvas=document.getElementById('mainChart');if(!canvas||typeof Chart==='undefined')return;
  const d=chartData[currentMetric][currentPeriod];
  const color=currentMetric==='earnings'?'#8b83e8':'#2dbd8f';
  const labels=d.labels.map(v=>__tlbl(v));
  const subs=d.sub||[];
  const n=d.values.length;const vis=Math.min(__VIS[currentPeriod]||7,n);
  const maxIdx=n-1;const minIdx=Math.max(0,n-vis);
  const hasZoom=!!(Chart.registry&&Chart.registry.plugins&&(()=>{try{return Chart.registry.plugins.get('zoom');}catch(e){return false;}})());
  const __curRange=vis;
  const __guardZoomOut=({chart})=>{const sx=chart.scales.x;if((sx.max-sx.min)>=__curRange){sx.options.min=minIdx;sx.options.max=maxIdx;chart.update('none');return false;}};
  const zoomOpts=hasZoom?{zoom:{pan:{enabled:true,mode:'x',threshold:10},zoom:{wheel:{enabled:true,speed:0.05,modifierKey:null},pinch:{enabled:true},mode:'x',onZoom:__guardZoomOut,onZoomStart:({chart,event})=>{if(event&&event.deltaY!=null&&event.deltaY>0)return false;}},limits:{x:{min:-0.5,max:n-0.5,minRange:1,maxRange:__curRange}}}}:{};
  const ctx2d=canvas.getContext('2d');const grad=ctx2d.createLinearGradient(0,0,0,canvas.height||220);grad.addColorStop(0,color+'66');grad.addColorStop(1,color+'00');
  mainChart=new Chart(canvas,{type:'line',data:{labels,datasets:[{data:d.values,borderColor:color,backgroundColor:grad,fill:true,tension:0.4,cubicInterpolationMode:'monotone',borderWidth:2.5,pointRadius:3,pointHoverRadius:6,pointBackgroundColor:color,pointBorderColor:'#fff',pointBorderWidth:1.5,spanGaps:true}]},options:{responsive:true,maintainAspectRatio:false,devicePixelRatio:Math.min(window.devicePixelRatio||1,2),animation:false,transitions:{zoom:{animation:{duration:0}},pan:{animation:{duration:0}},active:{animation:{duration:0}},show:{animation:{duration:0}},hide:{animation:{duration:0}}},interaction:{mode:'nearest',intersect:false,axis:'x'},plugins:Object.assign({legend:{display:false},decimation:{enabled:true,algorithm:'lttb',samples:80},tooltip:{animation:false,displayColors:false,padding:10,titleFont:{size:12,weight:'600'},bodyFont:{size:12},callbacks:{title:items=>{if(!items||!items[0])return '';const i=items[0].dataIndex;const lab=__tlbl(d.labels[i]||'');const s=subs[i]||'';return s?lab+' · '+s:lab;},label:ctx=>currentMetric==='earnings'?' '+(window.__lateenSelSym?window.__lateenSelSym():'£')+ctx.raw:' '+ctx.raw+' pcs'}}},zoomOpts),scales:{x:{min:minIdx,max:maxIdx,grid:{display:false},ticks:{font:{size:11},color:'#5e5c58',maxRotation:0,autoSkip:true,maxTicksLimit:vis+1}},y:{beginAtZero:true,grace:'5%',grid:{color:'rgba(255,255,255,0.04)'},ticks:{font:{size:10},color:'#5e5c58',maxTicksLimit:5,callback:v=>currentMetric==='earnings'?(window.__lateenSelSym?window.__lateenSelSym():'£')+v:v}}}}});
}
function buildRingChart(){const a=analyticsData[currentPeriod];const total=a.ok+a.fail;const okPct=total>0?Math.round((a.ok/total)*100):0;const failPct=total>0?100-okPct:0;document.getElementById('ring-pct').textContent=okPct+'%';document.getElementById('leg-ok').textContent=a.ok.toLocaleString();document.getElementById('leg-fail').textContent=a.fail.toLocaleString();const badge=document.getElementById('fail-badge');if(badge){badge.style.display=a.failPct>0?'inline-flex':'none';badge.style.background='#3a1a1a';badge.style.color='#e07070';}const bt=document.getElementById('fail-badge-text');if(bt)bt.textContent='−'+a.failPct+'% failure rate';if(ringChart)ringChart.destroy();ringChart=new Chart(document.getElementById('ringChart'),{type:'doughnut',data:{datasets:[{data:total>0?[okPct,failPct]:[0,100],backgroundColor:total>0?['#2dbd8f','#6b2424']:['#2a2a2a','#2a2a2a'],borderWidth:0,hoverOffset:0}]},options:{cutout:'72%',responsive:false,plugins:{legend:{display:false},tooltip:{enabled:false}},animation:{duration:500}}});}
function switchMetric(metric,el){currentMetric=metric;document.querySelectorAll('.ctoggle').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();}
function switchPeriod(period,el){currentPeriod=period;document.querySelectorAll('.ptab').forEach(b=>b.classList.remove('active'));el.classList.add('active');buildMainChart();buildRingChart();}

/* ── Browse ── */
const PLAT=.05;
const CN={NG:'Nigeria',GH:'Ghana',EG:'Egypt',KE:'Kenya',ZA:'South Africa',MA:'Morocco'};
let P=[];
let __favIds=new Set();
let __favOrder=[];
function dbToBrowse(r){const cur=r.currency||{symbol:'£',code:'GBP'};const photo=(r.photos&&r.photos[0])||null;const e=photo?`<img src="${photo}" alt="" style="width:100%;height:100%;object-fit:cover;border-radius:inherit"/>`:(cur.flag||'📦');const d={};Object.entries(r.delivery||{}).forEach(([code,z])=>{d[code]={cities:[],c:{},shipping:0,delivery:0};Object.entries(z.cities||{}).forEach(([city,v])=>{d[code].c[city]={s:Number(v.shipping)||0,d:Number(v.delivery)||0};d[code].cities.push(city);d[code].shipping=Number(v.shipping)||0;d[code].delivery=Number(v.delivery)||0;});});return{id:r.id,bid:r.business_id,biz:r.biz_name||'',bizPhone:r.biz_phone||'',e,ph:r.photos||[],n:r.name,cat:r.category||'',code:r.code||'',desc:r.description||'',pr:Number(r.price)||0,cur:{s:cur.symbol||'£',code:cur.code||'GBP'},pct:Number(r.comm_pct)||0,platformFee:Number(r.platform_fee)||0,q:Number(r.qty)||0,sv:__favIds.has(r.id),sz:r.sizes||[],cl:r.colors||[],d};}
async function loadBrowse(){if(!window.LateenAPI)return;try{const api=window.LateenAPI;if(api.listFavoriteIdsOrdered){__favOrder=await api.listFavoriteIdsOrdered();__favIds=new Set(__favOrder);}else{__favIds=await api.listFavoriteIds();__favOrder=[...__favIds];}const rows=await api.listBrowse();P=rows.map(dbToBrowse);rebuildProductsMap();if(typeof go==='function')go();if(typeof renderSaved==='function')renderSaved();}catch(e){console.error('[Lateen] loadBrowse',e);}}
function favSortedProducts(){const idx=new Map(__favOrder.map((id,i)=>[id,i]));return P.filter(p=>p.sv).sort((a,b)=>{const ai=idx.has(a.id)?idx.get(a.id):1e9;const bi=idx.has(b.id)?idx.get(b.id):1e9;return ai-bi;});}
const pctHtml=v=>`<span class="pct-inline" dir="ltr" data-no-i18n>${v}%</span>`;
function rebuildProductsMap(){PRODUCTS={};const sel=document.getElementById('f-product');const cur=sel?sel.value:'';const favs=favSortedProducts();if(sel){sel.innerHTML='<option value=""></option>'+favs.map(p=>`<option value="${p.id}">${p.n} · ${p.cur.s}${p.pr.toFixed(2)}</option>`).join('');if(cur&&P.find(p=>p.id===cur))sel.value=cur;}P.forEach(p=>{const delivery={};Object.entries(p.d).forEach(([code,z])=>{delivery[code]={cities:z.cities||Object.keys(z.c||{}),shipping:z.shipping||0,delivery:z.delivery||0,_per:z.c||{}};});PRODUCTS[p.id]={id:p.id,bid:p.bid,name:p.n,price:p.pr,pct:p.pct/100,sizes:p.sz,colors:p.cl,biz:p.biz,bizPhone:p.bizPhone,sym:p.cur.s,currency:{symbol:p.cur.s,code:p.cur.code},delivery};});if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();}
function __pkT(){const ar=__ar();return {sel:ar?'اختر منتجاً محفوظاً':'Select a saved product',title:ar?'المنتجات المحفوظة':'Saved products',search:ar?'ابحث في المنتجات المحفوظة…':'Search saved products…',commission:ar?'عمولة':'commission',noMatch:ar?'لا توجد نتائج مطابقة.':'No matches.',empty:ar?'لا توجد منتجات محفوظة بعد. اضغط على القلب في صفحة التصفح لحفظ منتج.':'No saved products yet. Tap the heart on a product in Browse to save it.',fieldLabel:ar?'اختر من منتجاتك المحفوظة':'Choose from your saved products',section:ar?'المنتج':'Product'};}
function syncProductPickerLabel(){const t=__pkT();const fl=document.getElementById('prod-field-label');if(fl)fl.textContent=t.fieldLabel;const sl=document.getElementById('prod-section-label');if(sl)sl.textContent=t.section;const sel=document.getElementById('f-product');if(!sel)return;const id=sel.value;const p=id?P.find(x=>x.id===id):null;const lbl=document.getElementById('prod-picker-label');const sub=document.getElementById('prod-picker-sub');const thumb=document.getElementById('prod-picker-thumb');if(!lbl||!sub||!thumb)return;if(!p){lbl.textContent=t.sel;lbl.style.color='var(--color-text-secondary)';sub.style.display='none';thumb.innerHTML='📦';}else{lbl.textContent=p.n;lbl.style.color='var(--color-text-primary)';sub.style.display='block';sub.innerHTML=`${p.cur.s}${p.pr.toFixed(2)} · ${pctHtml(p.pct)} ${t.commission}${p.biz?' · '+p.biz:''}`;thumb.innerHTML=p.e;}}
function openProductPicker(){const ov=document.getElementById('prod-picker-overlay');if(!ov)return;const t=__pkT();const ttl=document.getElementById('prod-picker-title');if(ttl)ttl.textContent=t.title;const s=document.getElementById('prod-picker-search');if(s){s.value='';s.setAttribute('placeholder',t.search);s.blur();}ov.classList.add('open');renderProductPicker('');__bindProductPickerList();}
function closeProductPicker(){const ov=document.getElementById('prod-picker-overlay');if(!ov)return;const s=document.getElementById('prod-picker-search');if(s)s.blur();ov.classList.remove('open');}
function renderProductPicker(q){const list=document.getElementById('prod-picker-list');if(!list)return;const t=__pkT();const favs=favSortedProducts();const qq=(q||'').trim().toLowerCase();const filtered=qq?favs.filter(p=>p.n.toLowerCase().includes(qq)||(p.cat||'').toLowerCase().includes(qq)||(p.biz||'').toLowerCase().includes(qq)||(p.code||'').toLowerCase().includes(qq)):favs;if(!filtered.length){list.innerHTML=`<div style="padding:30px 12px;text-align:center;color:var(--color-text-secondary);font-size:13px;line-height:1.5;">${favs.length?t.noMatch:t.empty}</div>`;return;}list.innerHTML=filtered.map(p=>`<button type="button" data-pid="${p.id}" class="product-card-saved" style="cursor:pointer;text-align:start;font-family:var(--font-sans);width:100%;-webkit-tap-highlight-color:transparent;touch-action:manipulation;"><div class="product-thumb" style="pointer-events:none;">${p.e}</div><div style="flex:1;min-width:0;pointer-events:none;"><div class="product-name">${p.n}</div><div class="product-meta">${p.cur.s}${p.pr.toFixed(2)} · ${pctHtml(p.pct)} ${t.commission}</div></div></button>`).join('');}
function __bindProductPickerList(){const list=document.getElementById('prod-picker-list');if(!list||list.__bound)return;list.__bound=true;const h=(e)=>{const btn=e.target&&e.target.closest&&e.target.closest('button[data-pid]');if(!btn)return;e.preventDefault();e.stopPropagation();const pid=btn.getAttribute('data-pid');if(pid)pickProduct(pid);};list.addEventListener('click',h);list.addEventListener('touchend',h,{passive:false});}
function pickProduct(id){const sel=document.getElementById('f-product');if(!sel)return;if(!Array.from(sel.options).some(o=>o.value===id)){const p=P.find(x=>x.id===id);if(p){const opt=document.createElement('option');opt.value=p.id;opt.textContent=`${p.n} · ${p.cur.s}${p.pr.toFixed(2)}`;sel.appendChild(opt);}}sel.value=id;closeProductPicker();syncProductPickerLabel();if(typeof onProductChange==='function')onProductChange();if(typeof persistOpenDraft==='function')setTimeout(persistOpenDraft,0);}
let __unsubBrowse=null,__unsubFavs=null,__unsubOrders=null,__unsubWallet=null;
let fc='',fct='',fs='',activeCat='',pc2='',pct2='',pss='',did=null;
const allC=()=>{const s=new Set();P.forEach(p=>Object.keys(p.d).forEach(c=>s.add(c)));return[...s];};
const citFor=c=>{const s=new Set();P.forEach(p=>{if(p.d[c])Object.keys(p.d[c].c).forEach(x=>s.add(x));});return[...s];};
function setCat(cat,el){activeCat=cat;document.querySelectorAll('[id^="cat-"]').forEach(e=>e.classList.remove('on'));el.classList.add('on');go();}
function go(){const si=document.getElementById('si');const q=(si?si.value||'':'').toLowerCase();let l=P.filter(p=>{const mq=!q||p.n.toLowerCase().includes(q);const mc=!fc||!!p.d[fc];const mct=!fct||(fc&&p.d[fc]&&!!p.d[fc].c[fct]);const mcat=!activeCat||p.cat===activeCat;return mq&&mc&&mct&&mcat;});if(fs==='ch')l.sort((a,b)=>b.pct-a.pct);else if(fs==='cl')l.sort((a,b)=>a.pct-b.pct);else if(fs==='ph')l.sort((a,b)=>b.pr-a.pr);else if(fs==='pl')l.sort((a,b)=>a.pr-b.pr);rg2(l);rr();ub();}
function cd(p){return`<div class="c" onclick="openD('${p.id}')"><div class="ci2">${p.e}<div style="position:absolute;bottom:0;right:0;display:flex;flex-direction:column;align-items:center;gap:3px;padding:8px 8px 7px;cursor:pointer;z-index:2;" onclick="event.stopPropagation();sv('${p.id}')"><div style="width:32px;height:32px;border-radius:50%;background:${p.sv?'#E24B4A':'rgba(0,0,0,0.55)'};border:1.5px solid ${p.sv?'#E24B4A':'rgba(255,255,255,0.3)'};display:flex;align-items:center;justify-content:center;transition:all .2s;"><svg width="16" height="16" viewBox="0 0 24 24" fill="${p.sv?'#fff':'none'}" stroke="#fff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg></div><span style="font-size:9px;color:rgba(255,255,255,.8);font-weight:500;font-family:var(--font-sans);">${p.sv?'Saved':'Save'}</span></div></div><div class="cb2"><div class="cn">${p.n}</div><div class="cr"><div class="cpr">${p.cur.s}${p.pr.toFixed(2)}</div><div class="cco">${p.pct}%</div></div></div></div>`;}
function rg2(l){const g=document.getElementById('mg');if(g)g.innerHTML=l.length?l.map(cd).join(''):'<div class="em">No products found.</div>';}
function rr(){const saved=P.filter(p=>p.sv);const rw=document.getElementById('rw');if(!rw)return;if(!saved.length){rw.style.display='none';return;}const cats=new Set(saved.map(p=>p.cat));const recs=P.filter(p=>!p.sv&&cats.has(p.cat)).slice(0,4);if(!recs.length){rw.style.display='none';return;}rw.style.display='block';document.getElementById('rg').innerHTML=recs.map(cd).join('');}
async function sv(id){const p=P.find(x=>x.id===id);if(!p||!window.LateenAPI)return;const willSave=!p.sv;p.sv=willSave;go();renderSaved();if(did===id)openD(id);try{if(willSave){await window.LateenAPI.addFavorite(id);__favIds.add(id);}else{await window.LateenAPI.removeFavorite(id);__favIds.delete(id);}}catch(e){console.error('[Lateen] favorite',e);p.sv=!willSave;go();renderSaved();}}
function ub(){const n=[fc,fct,fs].filter(Boolean).length;const b=document.getElementById('fbtn');if(!b)return;b.innerHTML=`<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="4" y1="6" x2="20" y2="6"/><line x1="8" y1="12" x2="16" y2="12"/><line x1="11" y1="18" x2="13" y2="18"/></svg> Filters${n?` (${n})`:''}`;b.classList.toggle('on',n>0);}
function openF(){pc2=fc;pct2=fct;pss=fs;rco();rci();rso();document.getElementById('fov').classList.add('open');}
function closeF(){document.getElementById('fov').classList.remove('open');}
function rco(){document.getElementById('co').innerHTML=`<div class="oo ${!pc2?'s':''}" onclick="sc('')">Any</div>`+allC().map(c=>`<div class="oo ${pc2===c?'s':''}" onclick="sc('${c}')">${CN[c]||c}</div>`).join('');}
function sc(c){pc2=c;pct2='';rco();rci();}
function rci(){const s=document.getElementById('cis');if(!pc2){s.style.display='none';return;}s.style.display='block';document.getElementById('cio').innerHTML=`<div class="oo ${!pct2?'s':''}" onclick="sct('')">Any city</div>`+citFor(pc2).map(c=>`<div class="oo ${pct2===c?'s':''}" onclick="sct('${c}')">${c}</div>`).join('');}
function sct(c){pct2=c;rci();}
function pk(k){pss=pss===k?'':k;rso();}
function rso(){['ch','cl','ph','pl'].forEach(k=>{document.getElementById('s'+k).classList.toggle('s',pss===k);});}
function apF(){fc=pc2;fct=pct2;fs=pss;closeF();go();}
function rsF(){pc2='';pct2='';pss='';fc='';fct='';fs='';rco();rci();rso();closeF();go();}
function openD(id){did=id;const p=P.find(x=>x.id===id);const s=p.cur.s;const earn=+(p.pr*p.pct/100).toFixed(2);const plat=+(p.pr*PLAT).toFixed(2);const fee=+(earn+plat).toFixed(2);const cities=Object.values(p.d).flatMap(z=>Object.keys(z.c));const low=p.q>0&&p.q<=20;const descBlock=p.desc?`<div class="dse">Description</div><div style="font-size:13px;color:var(--color-text-primary);line-height:1.5;white-space:pre-wrap;margin-bottom:14px;">${p.desc.replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}</div>`:'';const ownerBlock=`<div class="dse">Business owner</div><div style="background:#0D0D0D;border:0.5px solid #3a2a10;border-radius:12px;padding:12px;margin-bottom:14px;"><div style="font-size:14px;font-weight:500;color:#c9923a;margin-bottom:4px;">${(p.biz||'Unknown shop').replace(/[<>]/g,'')}</div>${p.bizPhone?`<div style="font-size:12px;color:var(--color-text-secondary);">Phone: <span style="color:var(--color-text-primary);font-weight:500;">${p.bizPhone.replace(/[<>]/g,'')}</span></div>`:''}${p.code?`<div style="font-size:11px;color:var(--color-text-tertiary);margin-top:4px;">Product code: ${p.code.replace(/[<>]/g,'')}</div>`:''}</div>`;document.getElementById('ds').innerHTML=`<div class="dp">${p.e}<div class="dh"><div class="dhb"></div></div></div><div class="db"><div class="dn">${p.n}</div><div class="ec"><div class="el">Your earning per sale</div><div class="ea">${s}${earn.toFixed(2)}</div><div class="eb"><div class="ei">Commission <span>${p.pct}%</span></div><div class="ei">Fee to collect <span>${s}${fee.toFixed(2)}</span></div><div class="ei">Platform fee <span>${s}${plat.toFixed(2)}</span></div></div></div><div class="sg"><div class="dt"><div class="dl">Price</div><div class="dv">${s}${p.pr.toFixed(2)}</div></div><div class="dt"><div class="dl">Commission</div><div class="dv pu">${p.pct}%</div></div><div class="dt"><div class="dl">In stock</div><div class="dv ${low?'am':''}">${p.q}${low?' ⚠':''}</div></div><div class="dt"><div class="dl">Ships to</div><div class="dv">${cities.length} cities</div></div></div>${descBlock}${ownerBlock}${p.sz.length?`<div class="dse">Sizes</div><div class="ch">${p.sz.map(x=>`<span class="chi">${x}</span>`).join('')}</div>`:''}${p.cl.length?`<div class="dse">Colours</div><div class="ch">${p.cl.map(x=>`<span class="chi">${x}</span>`).join('')}</div>`:''}<div class="dse">Delivery</div>${Object.entries(p.d).map(([code,z])=>`<div class="zb"><div class="zh">${CN[code]||code}</div>${Object.entries(z.c).map(([city,c])=>`<div class="zr"><span class="zn">${city}</span><span class="zc">Ship <span>${s}${Number(c.s).toFixed(2)}</span> · Deliv <span>${s}${Number(c.d).toFixed(2)}</span></span></div>`).join('')}</div>`).join('')}</div><div class="da"><button class="bsv ${p.sv?'sv':''}" onclick="sv('${p.id}')"><svg width="15" height="15" viewBox="0 0 24 24" fill="${p.sv?'#e07070':'none'}" stroke="${p.sv?'#e07070':'currentColor'}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg>${p.sv?'Saved':'Save'}</button><button class="blk" id="dlb" onclick="cpL()">Get my link</button></div>`;document.getElementById('dov').classList.add('open');}
function cpL(){const b=document.getElementById('dlb');b.textContent='Copied!';b.classList.add('cp');setTimeout(()=>{b.textContent='Get my link';b.classList.remove('cp');},2000);}
function closeD(){document.getElementById('dov').classList.remove('open');did=null;}
function onCam(i){if(!i.files.length)return;document.getElementById('cam').classList.add('open');document.getElementById('clb').textContent='Analysing image…';document.getElementById('cem').textContent='';document.getElementById('cnm').textContent='';setTimeout(()=>{const m=P[Math.floor(Math.random()*P.length)];document.getElementById('cem').textContent=m.e;document.getElementById('cnm').textContent='Found: '+m.n;document.getElementById('clb').textContent='Tap to open';document.getElementById('cnm').onclick=()=>{closeCam();openD(m.id);};},1400);i.value='';}
function closeCam(){document.getElementById('cam').classList.remove('open');}
function renderSaved(){const saved=P.filter(p=>p.sv);const c=document.getElementById('saved-list');const t=__pkT();if(!c)return;if(!saved.length){c.innerHTML=`<div class="saved-empty"><div class="saved-empty-icon">🤍</div>No saved products yet.<br>Browse and tap the heart to save products you want to market.</div>`;return;}c.innerHTML=`<div class="products-list">${saved.map(p=>`<div class="product-card-saved"><div class="product-thumb">${p.e}</div><div style="flex:1"><div class="product-name">${p.n}</div><div class="product-meta">${p.cur.s}${p.pr.toFixed(2)} · ${pctHtml(p.pct)} ${t.commission}</div><button class="copy-link-btn" onclick="this.textContent='Copied!';this.classList.add('copied');setTimeout(()=>{this.textContent='Copy link';this.classList.remove('copied');},2000)">Copy link</button></div><button class="save-btn" onclick="sv('${p.id}')"><svg width="16" height="16" viewBox="0 0 24 24" fill="#E24B4A" stroke="#E24B4A" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg></button></div>`).join('')}</div>`;}

/* ── Orders ── */
const PLATFORM_FEE_RATE=0.05;
let PRODUCTS={};
const COUNTRY_NAMES={NG:'Nigeria',GH:'Ghana',EG:'Egypt',KE:'Kenya',ZA:'South Africa'};
let currentProduct=null,currentDelivery=null,qty=1,selectedSize='',selectedColor='',depositConfirmed=null,hasReceipt=false,receiptUrl='',orders=[],editingId=null;
const fmt=n=>'£'+parseFloat(n||0).toFixed(2);
const fmtS=(sym,n)=>(sym||'£')+parseFloat(n||0).toFixed(2);
const fmtO=(o,n)=>fmtS(o&&o._sym,n);
const genCode=()=>'ORD-'+Math.random().toString(36).substr(2,6).toUpperCase();
const today2=()=>{const d=new Date();return d.getDate()+'/'+(d.getMonth()+1)+'/'+d.getFullYear();};
function calcFee(prod,q){const commPerUnit=parseFloat((prod.price*prod.pct).toFixed(2));const platformPerUnit=parseFloat((prod.price*PLATFORM_FEE_RATE).toFixed(2));const feePerUnit=parseFloat((commPerUnit+platformPerUnit).toFixed(2));const totalFee=parseFloat((feePerUnit*q).toFixed(2));return{commPerUnit,platformPerUnit,feePerUnit,totalFee};}
function updateFeeCard(){if(!currentProduct)return;const{commPerUnit,platformPerUnit,feePerUnit,totalFee}=calcFee(currentProduct,qty);document.getElementById('fee-total').textContent=fmt(totalFee);document.getElementById('fee-qty-note').textContent=qty>1?fmt(feePerUnit)+' per unit × '+qty:'per unit';document.getElementById('fee-commission').textContent=fmt(commPerUnit);document.getElementById('fee-platform').textContent=fmt(platformPerUnit);document.getElementById('deposit-q-sub').textContent='Confirm receipt of '+fmt(totalFee)+' from the customer';}
function onProductChange(){const key=document.getElementById('f-product').value;selectedSize='';selectedColor='';qty=1;document.getElementById('qty-display').textContent='1';document.getElementById('f-country').value='';document.getElementById('f-city').value='';document.getElementById('f-city').disabled=true;document.getElementById('f-city').innerHTML='<option value="">— Select country first —</option>';['prod-info','biz-costs','fee-card'].forEach(id=>document.getElementById(id).style.display='none');['size-group','color-group','qty-row'].forEach(id=>document.getElementById(id).style.display='none');document.getElementById('location-fields').style.display='none';document.getElementById('delivery-section-label').style.display='none';document.getElementById('address-field').style.display='none';document.getElementById('no-delivery-note').style.display='none';document.getElementById('country-hint').textContent='';document.getElementById('city-hint').textContent='';if(!key){currentProduct=null;return;}currentProduct=PRODUCTS[key];const p=currentProduct;document.getElementById('pi-price').textContent=fmt(p.price);document.getElementById('pi-pct').textContent=Math.round(p.pct*100)+'%';document.getElementById('pi-earn').textContent=fmt(p.price*p.pct);document.getElementById('prod-info').style.display='block';document.getElementById('fee-card').style.display='block';document.getElementById('qty-row').style.display='flex';if(p.sizes.length){document.getElementById('size-group').style.display='block';document.getElementById('size-chips').innerHTML=p.sizes.map(s=>`<div class="vchip" onclick="selectVariant('size','${s}',this)">${s}</div>`).join('');}if(p.colors.length){document.getElementById('color-group').style.display='block';document.getElementById('color-chips').innerHTML=p.colors.map(c=>`<div class="vchip" onclick="selectVariant('color','${c}',this)">${c}</div>`).join('');}const avail=Object.keys(p.delivery);const cs=document.getElementById('f-country');cs.innerHTML='<option value="">— Select country —</option>';avail.forEach(code=>{const o=document.createElement('option');o.value=code;o.textContent=COUNTRY_NAMES[code]||code;cs.appendChild(o);});document.getElementById('delivery-section-label').style.display='block';document.getElementById('location-fields').style.display='grid';document.getElementById('country-hint').textContent=avail.length+' countries available for this product';updateFeeCard();}
function onCountryChange(){const cc=document.getElementById('f-country').value;const cs=document.getElementById('f-city');const noteEl=document.getElementById('no-delivery-note');const bizCosts=document.getElementById('biz-costs');document.getElementById('city-hint').textContent='';cs.innerHTML='<option value="">— Select city —</option>';cs.disabled=true;bizCosts.style.display='none';noteEl.style.display='none';document.getElementById('address-field').style.display='none';currentDelivery=null;if(!cc||!currentProduct)return;const di=currentProduct.delivery[cc];if(!di){noteEl.textContent='This product is not available for delivery to '+(COUNTRY_NAMES[cc]||cc)+'. Please choose a different country.';noteEl.style.display='block';return;}di.cities.forEach(c=>{const o=document.createElement('option');o.value=c;o.textContent=c;cs.appendChild(o);});cs.disabled=false;document.getElementById('city-hint').textContent=di.cities.length+' cities available';}
function onCityChange(){const city=document.getElementById('f-city').value;const cc=document.getElementById('f-country').value;if(!city||!cc||!currentProduct)return;const di=currentProduct.delivery[cc];if(!di)return;const per=(di._per&&di._per[city])?{shipping:di._per[city].s,delivery:di._per[city].d}:{shipping:di.shipping,delivery:di.delivery};currentDelivery={...di,...per,city,country:COUNTRY_NAMES[cc]||cc,countryCode:cc};document.getElementById('bc-shipping').textContent=fmt(per.shipping);document.getElementById('bc-delivery').textContent=fmt(per.delivery);document.getElementById('bc-note').textContent='For '+city+', '+(COUNTRY_NAMES[cc]||cc)+' · set by business owner';document.getElementById('biz-costs').style.display='block';document.getElementById('address-field').style.display='block';updateSubmitState();if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();}
function changeQty(d){qty=Math.max(1,qty+d);document.getElementById('qty-display').textContent=qty;updateFeeCard();persistOpenDraft();}
function selectVariant(type,val,el){const g=type==='size'?'size-chips':'color-chips';document.querySelectorAll('#'+g+' .vchip').forEach(c=>c.classList.remove('selected'));el.classList.add('selected');if(type==='size')selectedSize=val;else selectedColor=val;persistOpenDraft();}
function triggerUpload(){openReceiptPicker();}
function openReceiptPicker(){const ov=document.getElementById('receipt-picker-overlay');if(ov)ov.classList.add('open');}
function closeReceiptPicker(){const ov=document.getElementById('receipt-picker-overlay');if(ov)ov.classList.remove('open');}
function pickReceipt(src){closeReceiptPicker();const map={camera:'file-input-camera',gallery:'file-input-gallery',files:'file-input-files'};const el=document.getElementById(map[src]||'file-input');if(el){el.value='';el.click();}}
async function onFileUpload(input){if(!input.files.length)return;const file=input.files[0];const box=document.getElementById('upload-box');const lbl=document.getElementById('upload-label');lbl.classList.remove('done','err');box.classList.remove('has-file','error');box.classList.add('uploading');lbl.innerHTML='<span class="upload-spinner"></span>Uploading '+file.name+'…';if(!window.LateenAPI||!window.LateenAPI.uploadReceipt){box.classList.remove('uploading');box.classList.add('error');lbl.classList.add('err');lbl.textContent='Upload service not ready — refresh and try again';hasReceipt=false;receiptUrl='';input.value='';updateSubmitState();return;}try{receiptUrl=await window.LateenAPI.uploadReceipt(file);hasReceipt=true;box.classList.remove('uploading');box.classList.add('has-file');lbl.classList.add('done');lbl.textContent='✓ Receipt ready · '+file.name;document.getElementById('deposit-section').style.display='block';persistOpenDraft();updateSubmitState();}catch(e){console.error('[Lateen] uploadReceipt',e);box.classList.remove('uploading');box.classList.add('error');lbl.classList.add('err');lbl.textContent='Upload failed — tap to try again ('+(e.message||e)+')';hasReceipt=false;receiptUrl='';input.value='';updateSubmitState();}}
function setDeposit(val){depositConfirmed=val;document.getElementById('dep-yes').classList.toggle('active',val===true);document.getElementById('dep-no').classList.toggle('active',val===false);updateSubmitState();}
function updateSubmitState(){const btn=document.getElementById('submit-btn');if(!btn)return;btn.disabled=false;btn.style.opacity='1';btn.style.cursor='pointer';if(hasReceipt){btn.textContent='Send Order to Business Owner';btn.style.background='#2dbd8f';btn.style.color='#fff';btn.title='Receipt will go to admin for verification, then forwarded to the business owner.';}else{btn.textContent=editingId?'Save changes (Draft)':'Save as Draft';btn.style.background='#f0eeeb';btn.style.color='#0D0D0D';btn.title='Saved locally. Upload a receipt to send for verification.';}}
async function saveDraftNow(){await submitOrder({forceDraft:true});}
function openForm(order){editingId=order?order.id:null;resetForm();if(order)prefillForm(order);document.getElementById('form-title').textContent=order?'Edit order':'New order';document.getElementById('submit-btn').textContent=order?'Save changes':'Add order';document.getElementById('form-overlay').classList.add('open');['f-name','f-phone','f-whatsapp','f-address','f-notes'].forEach(id=>{const el=document.getElementById(id);if(el&&!el.__wired){el.addEventListener('input',()=>{updateSubmitState();persistOpenDraft();});el.__wired=true;}});['f-product','f-country','f-city'].forEach(id=>{const el=document.getElementById(id);if(el&&!el.__wiredPersist){el.addEventListener('change',()=>setTimeout(persistOpenDraft,0));el.__wiredPersist=true;}});updateSubmitState();}
function closeForm(){document.getElementById('form-overlay').classList.remove('open');resetForm();}
function resetForm(){['f-name','f-phone','f-whatsapp','f-address','f-notes'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});document.getElementById('f-product').value='';document.getElementById('f-country').value='';document.getElementById('f-city').innerHTML='<option value="">— Select country first —</option>';document.getElementById('f-city').disabled=true;['prod-info','biz-costs','fee-card'].forEach(id=>document.getElementById(id).style.display='none');['size-group','color-group','qty-row'].forEach(id=>document.getElementById(id).style.display='none');document.getElementById('location-fields').style.display='none';document.getElementById('delivery-section-label').style.display='none';document.getElementById('address-field').style.display='none';document.getElementById('no-delivery-note').style.display='none';document.getElementById('deposit-section').style.display='none';document.getElementById('upload-box').classList.remove('has-file');document.getElementById('upload-label').textContent='Tap to upload receipt';document.getElementById('upload-label').classList.remove('done');document.getElementById('file-input').value='';document.getElementById('dep-yes').classList.remove('active');document.getElementById('dep-no').classList.remove('active');document.getElementById('qty-display').textContent='1';document.getElementById('country-hint').textContent='';document.getElementById('city-hint').textContent='';currentProduct=null;currentDelivery=null;qty=1;selectedSize='';selectedColor='';depositConfirmed=null;hasReceipt=false;receiptUrl='';if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();}
function prefillForm(o){document.getElementById('f-name').value=o.customerName;document.getElementById('f-phone').value=o.phone;document.getElementById('f-whatsapp').value=o.whatsapp||'';document.getElementById('f-product').value=o.productKey;document.getElementById('f-notes').value=o.notes||'';hasReceipt=!!o.hasReceipt;receiptUrl=o.receiptUrl||'';if(hasReceipt){const box=document.getElementById('upload-box');const lbl=document.getElementById('upload-label');if(box){box.classList.add('has-file');}if(lbl){lbl.classList.add('done');lbl.textContent='✓ Receipt already uploaded';}document.getElementById('deposit-section').style.display='block';}onProductChange();qty=o.qty||1;document.getElementById('qty-display').textContent=qty;document.getElementById('f-country').value=o.countryCode;onCountryChange();setTimeout(()=>{document.getElementById('f-city').value=o.city;onCityChange();document.getElementById('f-address').value=o.address||'';selectedSize=o.size||'';selectedColor=o.color||'';if(selectedSize)document.querySelectorAll('#size-chips .vchip').forEach(c=>{if(c.textContent===selectedSize)c.classList.add('selected');});if(selectedColor)document.querySelectorAll('#color-chips .vchip').forEach(c=>{if(c.textContent===selectedColor)c.classList.add('selected');});updateFeeCard();updateSubmitState();},50);}
function draftKey(){return'lateen_drafts_'+((window.LateenAPI&&window.LateenAPI.userId)||'anon');}
function loadDrafts(){try{return JSON.parse(localStorage.getItem(draftKey())||'[]');}catch(e){return[];}}
function saveDrafts(arr){try{localStorage.setItem(draftKey(),JSON.stringify(arr));}catch(e){}}
function upsertDraft(o){const arr=loadDrafts();const i=arr.findIndex(x=>x.id===o.id);if(i!==-1)arr[i]=o;else arr.unshift(o);saveDrafts(arr);}function buildLocalOrder(status){const name=(document.getElementById('f-name')?.value||'').trim();const phone=(document.getElementById('f-phone')?.value||'').trim();const prodKey=document.getElementById('f-product')?.value||'';const p=currentProduct||(prodKey?PRODUCTS[prodKey]:null);const fee=p?calcFee(p,qty):{commPerUnit:0,platformPerUnit:0,feePerUnit:0,totalFee:0};const ship=currentDelivery?currentDelivery.shipping:0;const deliv=currentDelivery?currentDelivery.delivery:0;const total=p?parseFloat((p.price*qty+ship+deliv).toFixed(2)):0;const existing=editingId?orders.find(o=>o.id===editingId):null;return{id:editingId||(existing&&existing.id)||genCode(),dbId:existing?existing.dbId:undefined,reserveDate:(existing&&existing.reserveDate)||today2(),customerName:name,phone,whatsapp:(document.getElementById('f-whatsapp')?.value||'').trim(),countryCode:currentDelivery?currentDelivery.countryCode:(existing&&existing.countryCode)||'',country:currentDelivery?currentDelivery.country:(existing&&existing.country)||'',city:currentDelivery?currentDelivery.city:(existing&&existing.city)||'',address:(document.getElementById('f-address')?.value||'').trim(),productKey:prodKey,productName:p?p.name:(existing&&existing.productName)||'(no product)',price:p?p.price:0,pct:p?p.pct:0,earn:fee.commPerUnit,shipping:ship,delivery:deliv,size:selectedSize,color:selectedColor,qty,total,feePerUnit:fee.feePerUnit,totalFee:fee.totalFee,commPerUnit:fee.commPerUnit,platformPerUnit:fee.platformPerUnit,notes:(document.getElementById('f-notes')?.value||'').trim(),bizName:p?p.biz:'',bizPhone:p?p.bizPhone:'',hasReceipt,receiptUrl,depositConfirmed:status==='pending',payDate:status==='pending'?today2():null,_status:status,_isDraft:status==='draft'&&!(existing&&existing.dbId),adminNotes:existing&&existing.adminNotes||'',receiptUploadedAt:hasReceipt?((existing&&existing.receiptUploadedAt)||new Date().toISOString()):null,reviewedAt:existing&&existing.reviewedAt||null,_sym:p&&p.currency?p.currency.symbol:(existing&&existing._sym)||'£'};}function persistOpenDraft(){if(!document.getElementById('form-overlay')?.classList.contains('open'))return;const o=buildLocalOrder('draft');if(!o.customerName&&!o.phone&&!o.productKey&&!o.hasReceipt&&!o.notes)return;editingId=o.id;upsertDraft(o);}
function removeDraft(id){saveDrafts(loadDrafts().filter(x=>x.id!==id));}
async function submitOrder(opts){opts=opts||{};const name=(document.getElementById('f-name').value||'').trim();const phone=(document.getElementById('f-phone').value||'').trim();const prodKey=document.getElementById('f-product').value;const sendNow=hasReceipt&&!opts.forceDraft;if(sendNow&&(!name||!phone||!prodKey||!currentDelivery)){alert('To send for verification: please fill customer name, phone, product, country and city.');persistOpenDraft();return;}const p=currentProduct||(prodKey?PRODUCTS[prodKey]:null);const localOrder=buildLocalOrder(sendNow?'pending':'draft');const fee={commPerUnit:localOrder.commPerUnit,platformPerUnit:localOrder.platformPerUnit};const marketerConfirmedAt=sendNow?new Date().toISOString():null;const existing=editingId?orders.find(o=>o.id===editingId):null;const existingDbId=existing?existing.dbId:null;try{if(window.LateenAPI&&p&&p.bid&&sendNow){const persistedFields={qty,unit_price:p.price,commission:fee.commPerUnit,platform_fee:fee.platformPerUnit,currency:p.currency||null,customer_name:name,customer_phone:phone,customer_whatsapp:localOrder.whatsapp||null,customer_city:currentDelivery.city,customer_country:currentDelivery.country,customer_country_code:currentDelivery.countryCode,customer_address:localOrder.address||null,customer_notes:localOrder.notes||null,shipping_fee:localOrder.shipping||0,delivery_fee:localOrder.delivery||0,size:selectedSize||null,color:selectedColor||null,receipt_url:receiptUrl||null,marketer_confirmed_at:marketerConfirmedAt,status:'pending',admin_notes:null};if(existingDbId){await window.LateenAPI.updateOrder(existingDbId,persistedFields);}else{const created=await window.LateenAPI.createOrder({product_id:p.id,business_id:p.bid,...persistedFields});if(created&&created.id){localOrder.dbId=created.id;localOrder._isDraft=false;}}removeDraft(localOrder.id);}else{upsertDraft(localOrder);}}catch(e){console.error('[Lateen] submitOrder',e);alert('Could not save order: '+(e.message||e));return;}if(editingId){const idx=orders.findIndex(o=>o.id===editingId);if(idx!==-1)orders[idx]={...orders[idx],...localOrder,id:editingId};else orders.unshift(localOrder);}else orders.unshift(localOrder);closeForm();renderOrders();recomputeAnalytics();refreshWallet();if(sendNow)loadOrders();}
function openInstr(orderId){const o=orders.find(x=>x.id===orderId);if(!o)return;document.getElementById('instr-sub').textContent=o.productName+' · '+o.city+', '+o.country;document.getElementById('instr-fee-amt').textContent=fmtO(o,o.totalFee);document.getElementById('instr-fee-breakdown').textContent='Includes your commission of '+fmtO(o,o.commPerUnit)+(o.qty>1?' × '+o.qty+' units':' per unit');document.getElementById('instr-overlay').classList.add('open');}
function closeInstr(){document.getElementById('instr-overlay').classList.remove('open');}
function copyText(btn,text){navigator.clipboard.writeText(text).catch(()=>{});btn.textContent='Copied!';btn.classList.add('done');setTimeout(()=>{btn.textContent='Copy';btn.classList.remove('done');},2000);}
function renderOrders(){const list=document.getElementById('orders-list');const empty=document.getElementById('empty-state');if(!orders.length){list.style.display='none';empty.style.display='flex';return;}empty.style.display='none';list.style.display='flex';list.innerHTML=orders.map(o=>{const st=o._status||'pending';const isDraft=st==='draft'||(!o.dbId&&!o.hasReceipt);const isPending=st==='pending'&&o.hasReceipt;const isApproved=st==='approved'||st==='confirmed'||st==='delivered';const isRejected=st==='rejected';const canEdit=isDraft||isRejected;const commLabel=isApproved?fmtO(o,o.commPerUnit*o.qty):(st==='cancelled'?'—':'Pending');const commColor=isApproved?'#2dbd8f':'var(--color-text-secondary)';let badge='';if(isDraft)badge=`<span class="pending-badge" style="background:#2a2236;color:#b8a8e8">📝 Draft · not sent</span>`;else if(isRejected)badge=`<span class="pending-badge" style="background:#3a1a1a;color:#e07070">✕ Receipt rejected</span>`;else if(isApproved)badge=`<span class="paid-badge"><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>✓ Approved · forwarded to business</span>`;else if(isPending)badge=`<span class="pending-badge" style="background:#2a2310;color:#e0c070">⏳ Pending verification by admin</span>`;else badge=`<span class="pending-badge">Awaiting business</span>`;const adminNoteBlock=isRejected&&o.adminNotes?`<div class="oc-notes" style="background:#2a1313;color:#e0a0a0;border:0.5px solid #6b2424;">⚠ Admin: ${(o.adminNotes+'').replace(/[<>]/g,'')}</div>`:'';const upTs=o.receiptUploadedAt?'<div class="oc-field-label">Receipt uploaded: '+new Date(o.receiptUploadedAt).toLocaleString()+'</div>':'';const apTs=o.reviewedAt?'<div class="oc-field-label">Reviewed: '+new Date(o.reviewedAt).toLocaleString()+'</div>':'';const action=isDraft?`<button class="how-btn" onclick="editOrder('${o.id}')">Add receipt &amp; send</button>`:(isRejected?`<button class="how-btn" onclick="editOrder('${o.id}')">Re-upload receipt</button>`:`<button class="how-btn" onclick="openInstr('${o.id}')">How to collect fee</button>`);return`<div class="order-card ${isApproved?'paid':''} ${isDraft?'draft':''}"><div class="oc-top"><span class="oc-code">${o.id} · ${o.reserveDate}</span><div class="oc-actions"><div class="oc-btn ${canEdit?'':'disabled'}" onclick="${canEdit?`editOrder('${o.id}')`:''}" title="Edit"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--color-text-primary)" stroke-width="2" stroke-linecap="round"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></div><div class="oc-btn ${canEdit?'':'disabled'}" onclick="${canEdit?`deleteOrder('${o.id}')`:''}" title="Delete"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="${canEdit?'#e07070':'var(--color-text-secondary)'}" stroke-width="2" stroke-linecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6M14 11v6"/></svg></div></div></div><div class="oc-customer">${o.customerName||'(no customer yet)'}</div><div class="oc-phone">${o.phone||''}${o.whatsapp?' · WA: '+o.whatsapp:''}</div><div class="oc-row"><span class="oc-chip">${o.city||'—'}, ${o.country||'—'}</span>${o.address?`<span class="oc-chip">${o.address}</span>`:''}</div><div class="oc-divider"></div><div class="oc-row"><span class="oc-chip purple">${o.productName}</span>${o.size?`<span class="oc-chip">Size: ${o.size}</span>`:''}${o.color?`<span class="oc-chip">Colour: ${o.color}</span>`:''}<span class="oc-chip">Qty: ${o.qty}</span></div><div class="oc-grid"><div><div class="oc-field-label">Price per unit</div><div class="oc-field-value">${fmtO(o,o.price)}</div></div><div><div class="oc-field-label">Total to pay</div><div class="oc-field-value">${fmtO(o,o.total)}</div></div><div><div class="oc-field-label">Shipping (${o.city||'—'})</div><div class="oc-field-value">${fmtO(o,o.shipping)}</div></div><div><div class="oc-field-label">Delivery</div><div class="oc-field-value">${fmtO(o,o.delivery)}</div></div><div><div class="oc-field-label">Your commission${o.qty>1?' (×'+o.qty+')':''}</div><div class="oc-field-value" style="color:${commColor}">${commLabel}</div></div></div>${upTs}${apTs}${o.notes?`<div class="oc-notes">Note: ${o.notes}</div>`:''}${adminNoteBlock}<div class="oc-divider"></div><div class="oc-footer">${badge}${action}</div></div>`;}).join('');}
function editOrder(id){const o=orders.find(x=>x.id===id);if(o)openForm(o);}
function deleteOrder(id){const o=orders.find(x=>x.id===id);if(o&&!o.dbId)removeDraft(id);orders=orders.filter(x=>x.id!==id);renderOrders();}
function dbToOrder(r){const p=PRODUCTS[r.product_id]||{};const cur=r.currency||p.currency||{symbol:'£',code:'GBP'};const sym=cur.symbol||'£';const curCode=cur.code||'GBP';const name=p.name||'Product';const price=Number(r.unit_price)||0;const pct=p.pct||(price>0?Number(r.commission)/price:0);const q=Number(r.qty)||1;const commPerUnit=Number(r.commission)||0;const platformPerUnit=Number(r.platform_fee)||0;const feePerUnit=parseFloat((commPerUnit+platformPerUnit).toFixed(2));const totalFee=parseFloat((feePerUnit*q).toFixed(2));const di=p.delivery&&p.delivery[r.customer_country_code||r.customer_country]?p.delivery[r.customer_country_code||r.customer_country]:null;const per=Number(r.shipping_fee)||Number(r.delivery_fee)?{shipping:Number(r.shipping_fee)||0,delivery:Number(r.delivery_fee)||0}:(di&&di._per&&di._per[r.customer_city]?{shipping:di._per[r.customer_city].s,delivery:di._per[r.customer_city].d}:{shipping:di?di.shipping:0,delivery:di?di.delivery:0});const created=r.created_at?new Date(r.created_at):new Date();const reserveDate=created.getDate()+'/'+(created.getMonth()+1)+'/'+created.getFullYear();const confirmed=!!r.marketer_confirmed_at;const mc=r.marketer_confirmed_at?new Date(r.marketer_confirmed_at):null;return{id:'ORD-'+String(r.id).slice(0,6).toUpperCase(),dbId:r.id,reserveDate,customerName:r.customer_name||'',phone:r.customer_phone||'',whatsapp:r.customer_whatsapp||'',countryCode:r.customer_country_code||'',country:r.customer_country||'',city:r.customer_city||'',address:r.customer_address||'',productKey:r.product_id,productName:name,price,pct,earn:commPerUnit,shipping:per.shipping,delivery:per.delivery,size:r.size||'',color:r.color||'',qty:q,total:parseFloat((price*q+per.shipping+per.delivery).toFixed(2)),feePerUnit,totalFee,commPerUnit,platformPerUnit,notes:r.customer_notes||'',bizName:p.biz||'',bizPhone:p.bizPhone||'',hasReceipt:!!r.receipt_url,receiptUrl:r.receipt_url||'',depositConfirmed:confirmed?true:null,payDate:mc?(mc.getDate()+'/'+(mc.getMonth()+1)+'/'+mc.getFullYear()):null,_status:r.status,_sym:sym,_curCode:curCode,_createdAt:created,adminNotes:r.admin_notes||'',receiptUploadedAt:r.receipt_uploaded_at||null,reviewedAt:r.reviewed_at||null};}
async function loadOrders(){const drafts=loadDrafts();if(!window.LateenAPI||!window.LateenAPI.listMyOrders){orders=drafts;renderOrders();refreshWallet();return;}try{const rows=await window.LateenAPI.listMyOrders();const mine=rows.filter(r=>r.marketer_id===window.LateenAPI.userId);const sentDbIds=new Set(mine.map(r=>r.id));orders=[...drafts.filter(d=>!d.dbId||!sentDbIds.has(d.dbId)),...mine.map(dbToOrder)];renderOrders();recomputeAnalytics();refreshWallet();}catch(e){console.error('[Lateen] loadOrders',e);if(!orders.length)orders=drafts;renderOrders();refreshWallet();}}
const __DOW=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const __MON=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
function __buildSeries(){
  const now=new Date();const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());
  let earliest=null;orders.forEach(o=>{const c=o._createdAt;if(c&&(!earliest||c<earliest))earliest=c;});
  const minDayStart=new Date(today);minDayStart.setDate(today.getDate()-29);
  let dayStart=earliest?new Date(earliest.getFullYear(),earliest.getMonth(),earliest.getDate()):new Date(today);
  if(dayStart>minDayStart)dayStart=minDayStart;
  const dayCount=Math.floor((today-dayStart)/86400000)+1;
  const minYear=now.getFullYear()-5;const startYear=earliest?Math.min(earliest.getFullYear(),minYear):minYear;
  const endYear=now.getFullYear();const yearCount=endYear-startYear+1;
  const monthsStart=new Date(startYear,0,1);const monthCount=(endYear-startYear)*12+now.getMonth()+1;
  const dayLabels=[],daySub=[];
  for(let i=0;i<dayCount;i++){const d=new Date(dayStart);d.setDate(dayStart.getDate()+i);dayLabels.push(__DOW[d.getDay()]);daySub.push(__ddmmyyyy(d));}
  const monLabels=[],monSub=[];
  for(let i=0;i<monthCount;i++){const m=new Date(monthsStart);m.setMonth(monthsStart.getMonth()+i);monLabels.push(__MON[m.getMonth()]);monSub.push(String(m.getFullYear()));}
  const yrLabels=[],yrSub=[];for(let i=0;i<yearCount;i++){yrLabels.push(String(startYear+i));yrSub.push('');}
  return{dayStart,dayCount,monthsStart,monthCount,startYear,yearCount,dayLabels,daySub,monLabels,monSub,yrLabels,yrSub};
}
function recomputeAnalytics(){
  const s=__buildSeries();
  const earnD=Array(s.dayCount).fill(0),earnM=Array(s.monthCount).fill(0),earnY=Array(s.yearCount).fill(0);
  const pcsD=Array(s.dayCount).fill(0),pcsM=Array(s.monthCount).fill(0),pcsY=Array(s.yearCount).fill(0);
  const ringD={ok:0,fail:0},ringM={ok:0,fail:0},ringY={ok:0,fail:0};
  let totEarn=0,totPieces=0,totOk=0,totDone=0;const totProducts=new Set();const earnByCur={};
  orders.forEach(o=>{
    const status=o._status||'pending';const c=o._createdAt;if(!c)return;
    const isEarn=status==='delivered';const isOk=status==='delivered';const isFail=status==='rejected';
    const earn=(o.commPerUnit||0)*(o.qty||0);
    if(isEarn){totEarn+=earn;const cc=o._curCode||'GBP';const ss=o._sym||'£';if(!earnByCur[cc])earnByCur[cc]={sym:ss,amount:0};earnByCur[cc].amount+=earn;}
    if(isOk){totPieces+=(o.qty||0);totOk++;if(o.productKey)totProducts.add(o.productKey);}
    if(isOk||isFail)totDone++;
    const di=Math.floor((new Date(c.getFullYear(),c.getMonth(),c.getDate())-s.dayStart)/86400000);
    if(di>=0&&di<s.dayCount){if(isEarn)earnD[di]+=earn;if(isOk){pcsD[di]+=o.qty;ringD.ok++;}if(isFail)ringD.fail++;}
    const mi=(c.getFullYear()-s.startYear)*12+c.getMonth();
    if(mi>=0&&mi<s.monthCount){if(isEarn)earnM[mi]+=earn;if(isOk){pcsM[mi]+=o.qty;ringM.ok++;}if(isFail)ringM.fail++;}
    const yi=c.getFullYear()-s.startYear;
    if(yi>=0&&yi<s.yearCount){if(isEarn)earnY[yi]+=earn;if(isOk){pcsY[yi]+=o.qty;ringY.ok++;}if(isFail)ringY.fail++;}
  });
  chartData.earnings.D={labels:s.dayLabels,sub:s.daySub,values:earnD.map(v=>+v.toFixed(2))};
  chartData.earnings.M={labels:s.monLabels,sub:s.monSub,values:earnM.map(v=>+v.toFixed(2))};
  chartData.earnings.Y={labels:s.yrLabels,sub:s.yrSub,values:earnY.map(v=>+v.toFixed(2))};
  chartData.pieces.D={labels:s.dayLabels,sub:s.daySub,values:pcsD};
  chartData.pieces.M={labels:s.monLabels,sub:s.monSub,values:pcsM};
  chartData.pieces.Y={labels:s.yrLabels,sub:s.yrSub,values:pcsY};
  [['D',ringD],['M',ringM],['Y',ringY]].forEach(([k,r])=>{const t=r.ok+r.fail;analyticsData[k]={ok:r.ok,fail:r.fail,failPct:t>0?Math.round((r.fail/t)*100):0};});
  const set=(id,v)=>{const el=document.getElementById(id);if(el)el.textContent=v;};
  window.__lateenEarnByCur=earnByCur;const __ks=Object.keys(earnByCur);if(!window.__lateenWalletCur||!earnByCur[window.__lateenWalletCur])window.__lateenWalletCur=__ks[0]||'GBP';const __sc=window.__lateenWalletCur;const __sd=earnByCur[__sc]||{sym:'£',amount:0};set('stat-earned',fmtS(__sd.sym,__sd.amount));set('stat-ok',totOk.toLocaleString());set('stat-ok-sub','of '+totDone+' order'+(totDone===1?'':'s'));set('stat-pieces',totPieces.toLocaleString());set('stat-pieces-sub',totProducts.size+' product'+(totProducts.size===1?'':'s'));
  if(typeof buildMainChart==='function')buildMainChart();if(typeof buildRingChart==='function')buildRingChart();
}

