async function openWithdraw(){document.getElementById('withdraw-overlay').classList.add('open');try{if(window.LateenAPI&&window.LateenAPI.getProfile){const p=await window.LateenAPI.getProfile();if(p){const set=(id,v)=>{const el=document.getElementById(id);if(el)el.value=v||'';};set('pd-method',p.payout_method);set('pd-bank',p.payout_bank_name);set('pd-holder',p.payout_account_holder);set('pd-acct',p.payout_account_number);set('pd-iban',p.payout_iban);set('pd-swift',p.payout_swift);set('pd-notes',p.payout_notes);}}}catch(e){console.error('[Lateen] load payout details',e);}}
function closeWithdraw(){document.getElementById('withdraw-overlay').classList.remove('open');}
async function confirmWithdraw(){const v=id=>{const el=document.getElementById(id);return el?el.value.trim():'';};const method=v('pd-method'),bank=v('pd-bank'),holder=v('pd-holder'),acct=v('pd-acct');if(!method||!bank||!holder||!acct){alert('Please fill in your payout method, bank, account holder, and account number so the admin can pay you.');return;}try{if(window.LateenAPI&&window.LateenAPI.updateProfile){await window.LateenAPI.updateProfile({payout_method:method,payout_bank_name:bank,payout_account_holder:holder,payout_account_number:acct,payout_iban:v('pd-iban')||null,payout_swift:v('pd-swift')||null,payout_notes:v('pd-notes')||null});}const w=await(window.LateenAPI&&window.LateenAPI.getWallet());const amt=w?Number(w.balance)||0:0;if(amt>0&&window.LateenAPI)await window.LateenAPI.requestPayout(amt);}catch(e){console.error('[Lateen] payout',e);alert('Failed: '+e.message);return;}closeWithdraw();const wb=document.querySelector('.withdraw-btn');if(wb){wb.textContent='Requested';wb.disabled=true;wb.style.opacity='0.5';}refreshWallet();}
window.__lateenSelSym=function(){const e=window.__lateenEarnByCur||{};const k=window.__lateenWalletCur||Object.keys(e)[0]||'GBP';return (e[k]&&e[k].sym)||'£';};
window.__selectWalletCur=function(c){window.__lateenWalletCur=c;refreshWallet();if(typeof recomputeAnalytics==='function')recomputeAnalytics();};
window.__toggleWalletCurList=function(){const l=document.getElementById('wallet-cur-list');const c=document.getElementById('wallet-cur-caret');if(!l)return;const open=l.style.display!=='none';l.style.display=open?'none':'block';if(c)c.style.transform=open?'rotate(0deg)':'rotate(180deg)';};
async function refreshWallet(){const totals=window.__lateenEarnByCur||{};const codes=Object.keys(totals);if(!window.__lateenWalletCur||!totals[window.__lateenWalletCur])window.__lateenWalletCur=codes[0]||'GBP';const sel=window.__lateenWalletCur;const sd=totals[sel]||{sym:'£',amount:0};const wa=document.querySelector('.wallet-amount');if(wa)wa.textContent=fmtS(sd.sym,sd.amount);const wp=document.getElementById('wallet-pending');if(wp)wp.textContent=sd.amount>0?'Available after admin receipt approval':'No approved receipt earnings yet';const wb=document.getElementById('wallet-breakdown');if(wb){if(codes.length>1){wb.style.display='block';const prev=document.getElementById('wallet-cur-list');const wasOpen=prev&&prev.style.display!=='none';const rows=codes.map(c=>{const a=c===sel;return `<button data-no-i18n onclick="__selectWalletCur('${c}')" style="display:flex;align-items:center;justify-content:space-between;gap:8px;width:100%;margin:0 0 6px 0;padding:10px 12px;border-radius:10px;border:0.5px solid ${a?'#7f77dd':'#232323'};background:${a?'#1a1830':'#0f0f0f'};color:#fff;font-size:12px;cursor:pointer;font-family:inherit;text-align:left"><span style="display:inline-flex;align-items:center;gap:8px"><span style="opacity:0.7">${totals[c].sym}</span><span>${c}</span></span><span style="font-weight:500">${fmtS(totals[c].sym,totals[c].amount)}</span></button>`;}).join('');wb.innerHTML=`<button data-no-i18n onclick="__toggleWalletCurList()" style="display:flex;align-items:center;justify-content:space-between;width:100%;padding:9px 12px;border-radius:10px;border:0.5px solid #232323;background:#141414;color:#fff;font-size:11px;cursor:pointer;font-family:inherit"><span style="display:inline-flex;align-items:center;gap:8px"><span style="opacity:0.55;letter-spacing:0.04em">EARNINGS BY CURRENCY</span><span style="opacity:0.5">·</span><span style="opacity:0.85">${codes.length} currencies</span></span><span id="wallet-cur-caret" style="display:inline-block;transition:transform .15s;opacity:0.7">▾</span></button><div id="wallet-cur-list" style="display:${wasOpen?'block':'none'};margin-top:8px">${rows}</div>`;const caret=document.getElementById('wallet-cur-caret');if(caret&&wasOpen)caret.style.transform='rotate(180deg)';}else{wb.style.display='none';wb.innerHTML='';}}const wd=document.getElementById('withdraw-amount');if(wd)wd.textContent=fmtS(sd.sym,sd.amount);}
async function refreshProfile(){if(!window.LateenAPI||!window.LateenAPI.getProfile)return;try{const p=await window.LateenAPI.getProfile();const name=(p&&p.full_name)||'';const initials=name?name.split(/\s+/).filter(Boolean).slice(0,2).map(s=>s[0].toUpperCase()).join(''):'··';const first=name?name.split(/\s+/)[0]:'there';['user-avatar','menu-avatar'].forEach(id=>{const el=document.getElementById(id);if(el)el.textContent=initials;});const g=document.getElementById('user-greet');if(g)g.textContent='Hey, '+first;const mn=document.getElementById('menu-name');if(mn)mn.textContent=name||'Welcome';const bn=document.getElementById('bank-name');if(bn&&name)bn.textContent=name;}catch(e){console.error('[Lateen] profile',e);}}

